prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(STRLEN(STR(?taskName)) > 0)
}
ORDER BY LCASE(STR(?taskName))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelId ?modelId2 ?task ?taskName ?taskType WHERE {
  { ?model a bboExt:Model ; tai:normalizedId ?modelId . FILTER(?modelId = "3c1c7ac2bf4042fe9cd4ed34ce14a188") }
  UNION
  { ?model a bboExt:Model ; tai:originalId ?modelId2 . FILTER(?modelId2 = "3c1c7ac2bf4042fe9cd4ed34ce14a188") }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?task a ?taskType ; tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?reachable ?reachName ?reachType WHERE {
  VALUES ?recordTask {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-59E2CFCD-9D63-49A7-ACD4-BFC6A59E71ED>
  }
  ?recordTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
  OPTIONAL { ?reachable bbo:name ?reachName . }
  OPTIONAL { ?reachable a ?reachType . }
}
LIMIT 25
